+//! Feishu connector error types.
+
+use std::time::Duration;
+
+use fcp_async_core::AsyncError;
+use fcp_core::FcpError;
+use fcp_sdk::migration::{ConnectorErrorMapping, classify_http_status};
+use thiserror::Error;
+
+/// Feishu connector errors.
+#[derive(Error, Debug)]
+pub enum FeishuError {
+    /// HTTP transport error.
+    #[error("HTTP error: {0}")]
+    Http(#[from] reqwest::Error),
+
+    /// JSON serialization/deserialization error.
+    #[error("JSON error: {0}")]
+    Json(#[from] serde_json::Error),
+
+    /// Feishu API returned an error response.
+    #[error("Feishu API error ({code}): {message}")]
+    Api { code: i32, message: String },
+
+    /// HTTP-level error from Feishu.
+    #[error("Feishu HTTP error ({status}): {message}")]
+    HttpStatus { status: u16, message: String },
+
+    /// Rate limited by Feishu API.
+    #[error("Rate limited, retry after {retry_after_ms}ms")]
+    RateLimited { retry_after_ms: u64 },
+
+    /// Authentication failure.
+    #[error("Unauthorized: {0}")]
+    Unauthorized(String),
+
+    /// Invalid input.
+    #[error("Invalid input: {0}")]
+    InvalidInput(String),
+
+    /// Async operation error (timeout, cancellation).
+    #[error("Async error: {0}")]
+    Async(String),
+
+    /// Configuration error.
+    #[error("Configuration error: {0}")]
+    Config(String),
+}
+
+impl FeishuError {
+    /// Whether this error is retryable.
+    pub fn is_retryable(&self) -> bool {
+        match self {
+            Self::Http(_) | Self::RateLimited { .. } | Self::Async(_) => true,
+            Self::HttpStatus { status, .. } => {
+                classify_http_status(*status, None).is_retryable()
+            }
+            // Feishu error codes: 99991400 = request throttled
+            Self::Api { code, .. } => *code == 99991400,
+            Self::Json(_)
+            | Self::Unauthorized(_)
+            | Self::InvalidInput(_)
+            | Self::Config(_) => false,
+        }
+    }
+
+    /// Suggested retry-after delay.
+    pub const fn retry_after(&self) -> Option<Duration> {
+        match self {
+            Self::RateLimited { retry_after_ms } => Some(Duration::from_millis(*retry_after_ms)),
+            _ => None,
+        }
+    }
+
+    /// Convert to FCP error taxonomy.
+    pub fn to_fcp_error(&self) -> FcpError {
+        match self {
+            Self::Http(e) => FcpError::External {
+                service: "feishu".into(),
+                message: e.to_string(),
+                status_code: e.status().map(|s| s.as_u16()),
+                retryable: self.is_retryable(),
+                retry_after: self.retry_after(),
+            },
+            Self::Json(e) => FcpError::Internal {
+                message: format!("JSON error: {e}"),
+            },
+            Self::Api { code, message } => FcpError::External {
+                service: "feishu".into(),
+                message: format!("API error {code}: {message}"),
+                status_code: None,
+                retryable: self.is_retryable(),
+                retry_after: None,
+            },
+            Self::HttpStatus { status, message } => FcpError::External {
+                service: "feishu".into(),
+                message: format!("HTTP {status}: {message}"),
+                status_code: Some(*status),
+                retryable: self.is_retryable(),
+                retry_after: None,
+            },
+            Self::RateLimited { retry_after_ms } => FcpError::RateLimited {
+                retry_after_ms: *retry_after_ms,
+                violation: None,
+            },
+            Self::Unauthorized(msg) => FcpError::Unauthorized {
+                code: 2001,
+                message: msg.clone(),
+            },
+            Self::InvalidInput(msg) => FcpError::InvalidRequest {
+                code: 1005,
+                message: msg.clone(),
+            },
+            Self::Async(msg) => FcpError::Internal {
+                message: format!("Async error: {msg}"),
+            },
+            Self::Config(msg) => FcpError::InvalidRequest {
+                code: 1001,
+                message: format!("Configuration error: {msg}"),
+            },
+        }
+    }
+}
+
+impl ConnectorErrorMapping for FeishuError {
+    fn from_async_error(error: AsyncError) -> Self {
+        match error {
+            AsyncError::Timeout { timeout_ms } => {
+                Self::Async(format!("operation timed out after {timeout_ms}ms"))
+            }
+            AsyncError::Cancelled => Self::Async("operation cancelled".into()),
+            other => Self::Async(format!("async error: {other}")),
+        }
+    }
+
+    fn to_fcp_error(&self) -> FcpError {
+        Self::to_fcp_error(self)
+    }
+
+    fn is_retryable(&self) -> bool {
+        Self::is_retryable(self)
+    }
+
+    fn retry_after(&self) -> Option<Duration> {
+        Self::retry_after(self)
+    }
+}
+
+pub type FeishuResult<T> = Result<T, FeishuError>;
+
+#[cfg(test)]
+mod tests {
+    use super::*;
+
+    #[test]
+    fn http_error_is_retryable() {
+        let err = FeishuError::Http(
+            reqwest::Client::new()
+                .get("://invalid")
+                .build()
