+    #[test]
+    fn config_error_not_retryable() {
+        let err = FeishuError::Config("missing credentials".into());
+        assert!(!err.is_retryable());
+    }
+
+    #[test]
+    fn from_async_timeout() {
+        let err = FeishuError::from_async_error(AsyncError::Timeout { timeout_ms: 5000 });
+        assert!(matches!(err, FeishuError::Async(_)));
+        assert!(err.is_retryable());
