+        let link_pattern = format!("[[{target_name}");
+        let mut backlinks = Vec::new();
+        self.find_backlinks(&self.vault_path, &link_pattern, note_path, &mut backlinks)?;
+        backlinks.sort_by(|a, b| a.source_path.cmp(&b.source_path));
+        Ok(backlinks)
