+//! Obsidian vault types.
+
+use serde::{Deserialize, Serialize};
+
+/// A note in the Obsidian vault.
+#[derive(Debug, Clone, Serialize, Deserialize)]
+pub struct Note {
+    /// Relative path within the vault (e.g., "folder/note.md").
+    pub path: String,
+    /// Note title (derived from filename without extension).
+    pub title: String,
+    /// Full markdown content.
+    #[serde(skip_serializing_if = "Option::is_none")]
+    pub content: Option<String>,
+    /// File size in bytes.
+    pub size: u64,
+    /// Last modified time (ISO 8601).
+    pub modified: String,
+    /// Created time (ISO 8601).
+    pub created: String,
+    /// Tags extracted from frontmatter/inline.
+    #[serde(default, skip_serializing_if = "Vec::is_empty")]
+    pub tags: Vec<String>,
+}
+
+/// A note listing entry (without content).
+#[derive(Debug, Clone, Serialize, Deserialize)]
+pub struct NoteEntry {
+    pub path: String,
+    pub title: String,
+    pub size: u64,
+    pub modified: String,
+    pub created: String,
+    #[serde(default, skip_serializing_if = "Vec::is_empty")]
+    pub tags: Vec<String>,
+}
+
+/// Search result for vault-wide text search.
+#[derive(Debug, Clone, Serialize, Deserialize)]
+pub struct SearchResult {
+    pub path: String,
+    pub title: String,
+    /// Matching line numbers and their content.
+    pub matches: Vec<SearchMatch>,
+}
+
+/// A single search match within a note.
+#[derive(Debug, Clone, Serialize, Deserialize)]
+pub struct SearchMatch {
+    pub line: usize,
+    pub text: String,
+}
+
+/// Tag with usage count.
+#[derive(Debug, Clone, Serialize, Deserialize)]
+pub struct TagInfo {
+    pub tag: String,
+    pub count: usize,
+}
+
+/// Backlink: another note that references the target.
+#[derive(Debug, Clone, Serialize, Deserialize)]
+pub struct Backlink {
+    pub source_path: String,
+    pub source_title: String,
+    pub line: usize,
+    pub context: String,
+}
+
+/// Vault health information.
+#[derive(Debug, Clone, Serialize, Deserialize)]
+pub struct VaultHealth {
+    pub vault_path: String,
+    pub note_count: usize,
+    pub total_size_bytes: u64,
+    pub readable: bool,
+    pub writable: bool,
+}
+
+#[cfg(test)]
