+            tags: vec!["daily".into(), "journal".into()],
+        };
+        let json = serde_json::to_value(&note).unwrap();
+        assert_eq!(json["path"], "daily/2026-03-21.md");
+        assert_eq!(json["title"], "2026-03-21");
