+    #[test]
+    fn note_entry_omits_content() {
+        let entry = NoteEntry {
+            path: "test.md".into(),
+            title: "test".into(),
+            size: 10,
+            modified: "2026-01-01T00:00:00Z".into(),
+            created: "2026-01-01T00:00:00Z".into(),
