+                match resp.json::<HelixResponse<T>>().await {
+                    Ok(r) => AttemptOutcome::Success(r),
+                    Err(e) => AttemptOutcome::Terminal(TwitchError::Http(e)),
+                }
+            }
+        })
+        .await
+    }
