+            }
+            OP_CHANNELS_GET => {
+                let broadcaster_id = req
+                    .input
+                    .get("broadcaster_id")
+                    .and_then(|v| v.as_str())
+                    .ok_or(FcpError::InvalidRequest {
+                        code: 1005,
+                        message: "Missing 'broadcaster_id' field".into(),
+                    })?;
+                let resp = client
+                    .get_channel(runtime, broadcaster_id)
+                    .await
+                    .map_err(|e| e.to_fcp_error())?;
+                let channel = resp.data.into_iter().next();
+                match channel {
+                    Some(c) => serde_json::to_value(c).map_err(|e| FcpError::Internal {
+                        message: format!("Failed to serialize channel: {e}"),
+                    })?,
+                    None => json!({ "error": "Channel not found" }),
+                }
+            }
+            OP_CHANNELS_MODIFY => {
+                let broadcaster_id = req
+                    .input
+                    .get("broadcaster_id")
+                    .and_then(|v| v.as_str())
+                    .ok_or(FcpError::InvalidRequest {
+                        code: 1005,
+                        message: "Missing 'broadcaster_id' field".into(),
+                    })?;
+                let modify_req = ModifyChannelRequest {
+                    title: req.input.get("title").and_then(|v| v.as_str()).map(String::from),
+                    game_id: req.input.get("game_id").and_then(|v| v.as_str()).map(String::from),
