+            }
+            OP_CLIPS_LIST => {
+                let broadcaster_id = req
+                    .input
+                    .get("broadcaster_id")
+                    .and_then(|v| v.as_str())
+                    .ok_or(FcpError::InvalidRequest {
+                        code: 1005,
+                        message: "Missing 'broadcaster_id' field".into(),
