+//! Twitch Helix API types.
+
+use serde::{Deserialize, Serialize};
+
+// ─────────────────────────────────────────────────────────────────────────────
+// OAuth token types
+// ─────────────────────────────────────────────────────────────────────────────
+
+/// OAuth2 client credentials token response.
+#[derive(Clone, Deserialize)]
+pub struct TokenResponse {
+    pub access_token: String,
+    pub expires_in: u64,
+    pub token_type: String,
+}
+
+impl std::fmt::Debug for TokenResponse {
+    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
+        f.debug_struct("TokenResponse")
+            .field("access_token", &"[REDACTED]")
+            .field("expires_in", &self.expires_in)
+            .field("token_type", &self.token_type)
+            .finish()
+    }
+}
+
+// ─────────────────────────────────────────────────────────────────────────────
+// Helix API response wrapper
+// ─────────────────────────────────────────────────────────────────────────────
+
+/// Generic Helix API response wrapper.
+#[derive(Debug, Clone, Serialize, Deserialize)]
+pub struct HelixResponse<T> {
+    pub data: Vec<T>,
+    #[serde(default)]
+    pub pagination: Option<Pagination>,
+}
+
+/// Pagination cursor.
+#[derive(Debug, Clone, Serialize, Deserialize)]
+pub struct Pagination {
+    #[serde(skip_serializing_if = "Option::is_none")]
+    pub cursor: Option<String>,
+}
+
+// ─────────────────────────────────────────────────────────────────────────────
+// Stream types
+// ─────────────────────────────────────────────────────────────────────────────
+
+/// A live stream.
+#[derive(Debug, Clone, Serialize, Deserialize)]
+pub struct Stream {
+    pub id: String,
+    pub user_id: String,
+    pub user_login: String,
+    pub user_name: String,
+    pub game_id: String,
+    pub game_name: String,
+    #[serde(rename = "type")]
+    pub stream_type: String,
+    pub title: String,
+    pub viewer_count: u64,
+    pub started_at: String,
+    pub language: String,
+    #[serde(default)]
+    pub tags: Vec<String>,
+    #[serde(default)]
+    pub is_mature: bool,
+}
+
+// ─────────────────────────────────────────────────────────────────────────────
+// User types
+// ─────────────────────────────────────────────────────────────────────────────
+
+/// A Twitch user.
+#[derive(Debug, Clone, Serialize, Deserialize)]
+pub struct User {
+    pub id: String,
+    pub login: String,
+    pub display_name: String,
+    #[serde(rename = "type")]
+    pub user_type: String,
+    pub broadcaster_type: String,
+    pub description: String,
+    pub profile_image_url: String,
+    pub offline_image_url: String,
+    pub view_count: u64,
+    pub created_at: String,
+}
+
+// ─────────────────────────────────────────────────────────────────────────────
+// Channel types
+// ─────────────────────────────────────────────────────────────────────────────
+
+/// Channel information.
+#[derive(Debug, Clone, Serialize, Deserialize)]
+pub struct Channel {
+    pub broadcaster_id: String,
+    pub broadcaster_login: String,
+    pub broadcaster_name: String,
+    pub broadcaster_language: String,
+    pub game_name: String,
+    pub game_id: String,
+    pub title: String,
+    pub delay: u32,
+    #[serde(default)]
+    pub tags: Vec<String>,
+    #[serde(default)]
+    pub content_classification_labels: Vec<String>,
+    #[serde(default)]
+    pub is_branded_content: bool,
+}
+
+/// Channel modification request.
+#[derive(Debug, Clone, Serialize, Deserialize)]
+pub struct ModifyChannelRequest {
+    #[serde(skip_serializing_if = "Option::is_none")]
+    pub game_id: Option<String>,
+    #[serde(skip_serializing_if = "Option::is_none")]
+    pub broadcaster_language: Option<String>,
+    #[serde(skip_serializing_if = "Option::is_none")]
+    pub title: Option<String>,
+    #[serde(skip_serializing_if = "Option::is_none")]
+    pub delay: Option<u32>,
+    #[serde(skip_serializing_if = "Option::is_none")]
+    pub tags: Option<Vec<String>>,
+}
+
+// ─────────────────────────────────────────────────────────────────────────────
+// Clip types
+// ─────────────────────────────────────────────────────────────────────────────
+
+/// A clip.
+#[derive(Debug, Clone, Serialize, Deserialize)]
+pub struct Clip {
+    pub id: String,
+    pub url: String,
+    pub embed_url: String,
+    pub broadcaster_id: String,
+    pub broadcaster_name: String,
+    pub creator_id: String,
+    pub creator_name: String,
+    pub game_id: String,
+    pub language: String,
+    pub title: String,
+    pub view_count: u64,
+    pub created_at: String,
+    pub duration: f64,
+}
+
+/// Response from creating a clip.
+#[derive(Debug, Clone, Serialize, Deserialize)]
+pub struct CreateClipResponse {
+    pub id: String,
+    pub edit_url: String,
+}
+
+// ─────────────────────────────────────────────────────────────────────────────
+// Chat types
+// ─────────────────────────────────────────────────────────────────────────────
+
+/// Chat message send request.
+#[derive(Debug, Clone, Serialize, Deserialize)]
+pub struct SendChatMessageRequest {
+    pub broadcaster_id: String,
+    pub sender_id: String,
+    pub message: String,
+}
+
+/// Chat message send response.
+#[derive(Debug, Clone, Serialize, Deserialize)]
+pub struct SendChatMessageResponse {
+    pub message_id: String,
+    pub is_sent: bool,
+    #[serde(skip_serializing_if = "Option::is_none")]
+    pub drop_reason: Option<DropReason>,
+}
+
+/// Reason a chat message was dropped.
+#[derive(Debug, Clone, Serialize, Deserialize)]
+pub struct DropReason {
+    pub code: String,
+    pub message: String,
+}
+
+// ─────────────────────────────────────────────────────────────────────────────
+// Game types
+// ─────────────────────────────────────────────────────────────────────────────
+
+/// A game/category.
+#[derive(Debug, Clone, Serialize, Deserialize)]
+pub struct Game {
+    pub id: String,
+    pub name: String,
+    pub box_art_url: String,
+    #[serde(default)]
+    pub igdb_id: String,
+}
+
+#[cfg(test)]
+mod tests {
+    use super::*;
+
+    #[test]
+    fn stream_deserialization() {
