+        });
+        let game: Game = serde_json::from_value(json).unwrap();
+        assert_eq!(game.name, "Fortnite");
+    }
+
+    #[test]
+    fn chat_message_response_deserialization() {
+        let json = serde_json::json!({
+            "message_id": "msg123",
