+            "id": "clip_id",
+            "edit_url": "https://clips.twitch.tv/edit/clip_id"
+        });
+        let resp: CreateClipResponse = serde_json::from_value(json).unwrap();
+        assert_eq!(resp.id, "clip_id");
+    }
